CREATE OR REPLACE FUNCTION fpb_tochar_format (as_value char, as_format char) RETURNS varchar AS $body$
DECLARE

  ls_return varchar(50);
  li_count_i integer;
  li_i integer := 1;
  li_count_j integer;
  ls_syntax varchar(50);
  ls_temp varchar(50);
  ls_ch varchar(1);
  ls_format varchar(50);
BEGIN
  ls_temp := as_format;
  -- '12345','#-##@##'
  li_count_i := len(replace(as_format,'#',null));
  li_count_j := len(as_format);
  ls_syntax := replace(ls_temp,'#',null);
  for i in 1..li_count_i loop
    ls_temp := replace(ls_temp,substr(ls_syntax,i,1),null);
  end loop;
  if len(ls_temp) < len(as_value) then
    li_count_i := len(ls_temp);
  else
    li_count_i := len(as_value);
  end if;
  ls_temp := null;

  for j in 1..li_count_j loop
    if substr(as_format,j,1) = '#' then
      ls_ch := substr(as_value,li_i,1);
      ls_temp := replace(as_format,'#',ls_ch);
      if li_i > li_count_i then exit;end if;
      li_i := li_i + 1;
      ls_return := ls_return || substr(ls_temp,j,1);
    else
      ls_return := ls_return || substr(as_format,j,1);
    end if;

  end loop;

  return ls_return;
exception WHEN OTHERS then CALL spa_dberror('FPB_TOCHAR_FORMAT');return ' ';
END;
$body$
